const body = $input.first().json.body || {};
const q = String(body.q || '').trim() || 'newer_than:7d';
const limit = Math.max(1, Math.min(50, parseInt(String(body.limit || 10), 10) || 10));
return [{ json: { q, limit } }];

const cfg = $('Configuration').first().json;
const items = $input.all();
if (!items.length || items[0].json?.error) {
  return [{ json: { ok: false, error: 'Gmail inaccessible.', emails: [], count: 0 } }];
}
const emails = items.map(item => {
  const m = item.json;
  // n8n Gmail node v2 expose From/Subject avec majuscule, internalDate en ms
  const fromRaw = m.From || m.from || '';
  const subject = m.Subject || m.subject || '(sans objet)';
  const date = m.internalDate
    ? new Date(parseInt(m.internalDate)).toISOString()
    : (m.Date || m.date || '');
  const match = fromRaw.match(/^(.*?)\s*<(.+?)>$/);
  return {
    id: m.id,
    from: fromRaw,
    from_name: (match?.[1] || fromRaw).trim(),
    from_email: match?.[2] || fromRaw,
    subject,
    date,
    snippet: (m.snippet || '').slice(0, 400),
    source: 'gmail'
  };
}).filter(e => e.id);
return [{ json: { ok: true, emails, count: emails.length, query: cfg.q } }];
